using VisualRelay.Core.Execution;

namespace VisualRelay.Tests;

// Resilience tests: TOCTOU race and Unicode path handling.
// Shares the partial class's git helpers (InitGitRepo, StageAndCommitSeed).
public sealed partial class GitCommitterAutoIncludeTests
{
    // ── stub IGitInvoker that injects a ghost path into ls-files output ──

    /// <summary>
    /// Wraps a real <see cref="IGitInvoker"/> and appends a non-existent path to
    /// <c>git ls-files --others --exclude-standard</c> output, simulating the
    /// TOCTOU race where a file is listed by the snapshot but deleted before
    /// <c>git add</c>.
    /// </summary>
    private sealed class StaleSnapshotGitInvoker : IGitInvoker
    {
        private readonly IGitInvoker _inner;
        private readonly string _ghostPath;

        public StaleSnapshotGitInvoker(IGitInvoker inner, string ghostPath)
        {
            _inner = inner;
            _ghostPath = ghostPath;
        }

        public async Task<(int ExitCode, string Output, bool TimedOut)> RunAsync(
            string rootPath,
            IEnumerable<string> arguments,
            CancellationToken cancellationToken,
            TimeSpan? timeout = null,
            IReadOnlyDictionary<string, string>? environment = null,
            CancellationToken killToken = default,
            Action<string>? onActivity = null)
        {
            var args = arguments as IReadOnlyList<string> ?? arguments.ToList();
            var result = await _inner.RunAsync(rootPath, args, cancellationToken, timeout, environment, killToken, onActivity);

            // Intercept ls-files --others --exclude-standard: append the ghost path
            // so it passes the snapshot-to-newAuthored filter, forcing the existence
            // gate to skip it before git add.
            if (args.Count == 3
                && args[0] == "ls-files"
                && args[1] == "--others"
                && args[2] == "--exclude-standard"
                && result.ExitCode == 0)
            {
                var output = result.Output;
                if (!string.IsNullOrWhiteSpace(output) && !output.EndsWith('\n'))
                    output += "\n";
                output += _ghostPath + "\n";
                return (result.ExitCode, output, result.TimedOut);
            }

            return result;
        }
    }

    // ── TOCTOU resilience ────────────────────────────────────────────

    [Fact]
    public async Task CommitAsync_SkipsVanishedFile_BetweenSnapshotAndAdd()
    {
        // The snapshot (git ls-files --others) and git add are not atomic.  A file
        // deleted between them must not fail the commit — the existence gate must
        // silently skip it.
        using var repo = TestRepository.Create();
        await InitGitRepo(repo.Root);
        Directory.CreateDirectory(Path.Combine(repo.Root, "src"));
        File.WriteAllText(Path.Combine(repo.Root, "src", "app.cs"), "old");
        await StageAndCommitSeed(repo.Root, "chore: seed");

        // Snapshot before the run: no untracked files.
        var preRunUntracked = await GitCommitter.CaptureUntrackedSnapshotAsync(
            repo.Root, CancellationToken.None);
        Assert.Empty(preRunUntracked);

        // Author a real file and modify a tracked file.
        File.WriteAllText(Path.Combine(repo.Root, "src", "app.cs"), "updated");
        File.WriteAllText(Path.Combine(repo.Root, "tests", "real-test.cs"), "// real");

        // Use a stub invoker that injects a ghost path into ls-files output,
        // simulating a file that existed at snapshot time but was deleted before
        // git add. The existence gate must skip it and the commit must succeed.
        var ghostRelPath = "ghost-vanished.cs";
        var stub = new StaleSnapshotGitInvoker(new GitInvoker(), ghostRelPath);

        var manifest = new[] { "src/app.cs" };

        var result = await GitCommitter.CommitAsync(
            repo.Root,
            "my-task",
            "abc123",
            ["feat: add widget"],
            manifest,
            [],
            commitToken: null,
            preRunUntracked,
            tasksDir: null,
            CancellationToken.None,
            gitInvoker: stub);

        Assert.True(result.Success, result.Error ?? "commit should succeed despite ghost path");
        var committed = TestGit.Run(repo.Root, "show", "--name-only", "--pretty=format:", "HEAD");
        Assert.Contains("src/app.cs", committed);
        Assert.Contains("tests/real-test.cs", committed);
        // The ghost path must NOT appear in the commit.
        Assert.DoesNotContain(ghostRelPath, committed);
    }

    // ── Unicode path handling ────────────────────────────────────────

    [Fact]
    public async Task CommitAsync_AutoIncludesFileWithUnicodeNarrowNoBreakSpace()
    {
        // A file whose name contains U+202F NARROW NO-BREAK SPACE (legitimate in
        // macOS filenames, emitted by ControlScreenshot) must be auto-included.
        using var repo = TestRepository.Create();
        await InitGitRepo(repo.Root);
        // Disable C-quoting so git emits the path verbatim.
        TestGit.Run(repo.Root, "config", "core.quotePath", "false");
        Directory.CreateDirectory(Path.Combine(repo.Root, "src"));
        File.WriteAllText(Path.Combine(repo.Root, "src", "app.cs"), "old");
        await StageAndCommitSeed(repo.Root, "chore: seed");

        var preRunUntracked = await GitCommitter.CaptureUntrackedSnapshotAsync(
            repo.Root, CancellationToken.None);
        Assert.Empty(preRunUntracked);

        // File name with U+202F between "05" and "AM" — mirrors the real
        // screenshot filename that triggered the original bug.
        var unicodeName = "Screenshot 2026-07-01 at 9.59.05\u202FAM.png";
        File.WriteAllText(Path.Combine(repo.Root, "src", "app.cs"), "updated");
        File.WriteAllText(Path.Combine(repo.Root, unicodeName), "screenshot content");

        var manifest = new[] { "src/app.cs" };

        var result = await GitCommitter.CommitAsync(
            repo.Root,
            "my-task",
            "abc123",
            ["feat: add widget"],
            manifest,
            [],
            commitToken: null,
            preRunUntracked,
            tasksDir: null,
            CancellationToken.None);

        Assert.True(result.Success, result.Error ?? "commit should succeed with U+202F filename");
        var committed = TestGit.Run(repo.Root, "show", "--name-only", "--pretty=format:", "HEAD");
        Assert.Contains(unicodeName, committed);
    }

    [Fact]
    public async Task CommitAsync_ExcludesTasksDirFileWithUnicodeInPath()
    {
        // A file dropped under the tasks dir whose path contains U+202F must be
        // excluded from auto-include — the tasks-dir guard must work regardless
        // of Unicode characters in the path.
        using var repo = TestRepository.Create();
        await InitGitRepo(repo.Root);
        TestGit.Run(repo.Root, "config", "core.quotePath", "false");
        Directory.CreateDirectory(Path.Combine(repo.Root, "src"));
        File.WriteAllText(Path.Combine(repo.Root, "src", "app.cs"), "old");
        await StageAndCommitSeed(repo.Root, "chore: seed");

        var preRunUntracked = await GitCommitter.CaptureUntrackedSnapshotAsync(
            repo.Root, CancellationToken.None);
        Assert.Empty(preRunUntracked);

        // Tasks dir with U+202F in the directory name.
        var tasksDirName = "llm-tasks";
        var unicodeSubDir = "unic\u202Fode-task";
        var tasksDirFilePath = $"{tasksDirName}/{unicodeSubDir}/task.md";

        File.WriteAllText(Path.Combine(repo.Root, "src", "app.cs"), "updated");
        File.WriteAllText(Path.Combine(repo.Root, "src", "genuine.cs"), "// authored");
        Directory.CreateDirectory(Path.Combine(repo.Root, tasksDirName, unicodeSubDir));
        File.WriteAllText(
            Path.Combine(repo.Root, tasksDirFilePath),
            "# user-dropped mid-run task with Unicode");

        var manifest = new[] { "src/app.cs" };

        // (a) commit with tasksDir guard active.
        var commit = await GitCommitter.CommitAsync(
            repo.Root, "task", "abc", ["feat: x"], manifest, [],
            commitToken: null, preRunUntracked,
            tasksDir: tasksDirName,
            CancellationToken.None);
        Assert.True(commit.Success, commit.Error);

        var committed = TestGit.Run(repo.Root, "show", "--name-only", "--pretty=format:", "HEAD");
        // Genuinely authored file outside tasks dir IS auto-included.
        Assert.Contains("src/genuine.cs", committed);
        // Tasks-dir file with Unicode in path is NOT in the commit.
        Assert.DoesNotContain(tasksDirFilePath, committed);

        // (b) FindUncommittedAuthoredFilesAsync must NOT report the tasks-dir file.
        var missed = await GitCommitter.FindUncommittedAuthoredFilesAsync(
            repo.Root, preRunUntracked,
            tasksDir: tasksDirName,
            CancellationToken.None);
        Assert.DoesNotContain(tasksDirFilePath, missed);
    }

    [Fact]
    public async Task CaptureUntrackedSnapshotAsync_FindsFileWithNarrowNoBreakSpace()
    {
        // The snapshot helper must correctly capture files with U+202F in the name
        // — no filtering at the ls-files level should drop such paths.
        using var repo = TestRepository.Create();
        await InitGitRepo(repo.Root);
        TestGit.Run(repo.Root, "config", "core.quotePath", "false");
        Directory.CreateDirectory(Path.Combine(repo.Root, "src"));
        File.WriteAllText(Path.Combine(repo.Root, "src", "app.cs"), "content");
        await StageAndCommitSeed(repo.Root, "chore: seed");

        var unicodeName = "Screenshot 2026-07-01 at 9.59.05\u202FAM.png";
        File.WriteAllText(Path.Combine(repo.Root, unicodeName), "screenshot content");

        var snapshot = await GitCommitter.CaptureUntrackedSnapshotAsync(
            repo.Root, CancellationToken.None);

        Assert.Contains(unicodeName, snapshot);
    }
}

